from flask import Flask, request, jsonify
import jwt
from jwt import PyJWTError

class JWTHandler:
    def __init__(self, algorithms):
        self.algorithms = algorithms

    def encode(self, payload, secret_key, algorithm):
        return jwt.encode(payload, secret_key, algorithm=algorithm)

    def decode(self, token, secret_key=None):
        for algorithm in self.algorithms:
            try:
                return jwt.decode(token, secret_key, algorithms=[algorithm])
            except PyJWTError:
                continue
        raise PyJWTError("Invalid token or signature.")

app = Flask(__name__)

# Initialize with supported algorithms
jwt_handler = JWTHandler(algorithms=['HS256', 'RS256'])

@app.route('/verify-token', methods=['POST'])
def verify_token():
    data = request.json
    token = data.get('token')
    secret_key = data.get('secret_key')

    try:
        payload = jwt_handler.decode(token, secret_key)
        return jsonify({'success': True, 'payload': payload}), 200
    except PyJWTError:
        return jsonify({'success': False, 'message': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)